class Solution:
    def countFairPairs(self, nums, lower, upper):
        nums = sorted(nums)
        n = len(nums)
        def count_le(bound):
            i, j = 0, n - 1
            cnt = 0
            while i < j:
                if nums[i] + nums[j] <= bound:
                    cnt += j - i
                    i += 1
                else:
                    j -= 1
            return cnt
        return count_le(upper) - count_le(lower - 1)

