var countFairPairs = function(nums, lower, upper) {
    const sorted = nums.slice().sort((a, b) => a - b);
    const n = sorted.length;
    const countLe = (bound) => {
        let i = 0, j = n - 1;
        let cnt = 0;
        while (i < j) {
            if (sorted[i] + sorted[j] <= bound) {
                cnt += j - i;
                i++;
            } else {
                j--;
            }
        }
        return cnt;
    };
    return countLe(upper) - countLe(lower - 1);
};
